+            .enter_critical(CriticalOpKind::CapabilityCheck, &format!("pre-{i}"))
+            .unwrap();
+        assert_eq!(guard.epoch, SecurityEpoch::from_raw(i - 1));
+        barrier.release_guard(&guard);
+
+        barrier
+            .transition_now(
